    plot(linspace(-0.75,1.25,size(data_opto_fac,2)),data_opto_sup(ii,:))
    line([0 0],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'g','LineWidth',0.5);
    line([0.5 0.5],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'g','LineWidth',0.5);
    xlim([-0.5 1]); %Define the xlimits
    % ylim([-10 40])
    set(gca,'fontSize',15,'FontName','Arial');
    ylabel('Spike rate (Hz)')
    xlabel('Time (s)')
    pause;
end
for ii=1:size(data_opto_NR,1)
    data_opto_NR(ii,:)= data_opto_NR(ii,:)-nanmean(data_opto_NR(ii,500:750));
end

for ii=1:size(data_opto_fac_delayed,1)
    data_opto_fac_delayed(ii,:)= data_opto_fac_delayed(ii,:)-nanmean(data_opto_fac_delayed(ii,500:750));
end




